package main

import (
	"encoding/xml"
	"fmt"
)

type Config struct {
	Settings []Setting `xml:"setting"`
}

type Setting struct {
	Name  string `xml:"name,attr"`
	Value string `xml:"value"`
}

func parseXMLConfig(xmlData []byte) (*Config, error) {
	var config Config
	err := xml.Unmarshal(xmlData, &config)
	if err != nil {
		return nil, fmt.Errorf("failed to parse XML: %w", err)
	}
	return &config, nil
}

func main() {
	xmlData := []byte(`
	<config>
		<setting name="host">localhost</setting>
		<setting name="port">8080</setting>
		<setting name="debug">true</setting>
	</config>`)
	config, err := parseXMLConfig(xmlData)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	for _, setting := range config.Settings {
		fmt.Printf("%s: %s\n", setting.Name, setting.Value)
	}
}